import{_ as a,o as s,c as r,a2 as i}from"./chunks/framework.Crpw6aS5.js";const h=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/dashboard.md","filePath":"fr/guide/dashboard.md"}'),t={name:"fr/guide/dashboard.md"};function l(o,e,u,d,n,p){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>Le Dashboard est la page d&#39;accueil de Nid. Il offre une vue d&#39;ensemble de votre boîte Gmail avec des graphiques interactifs.</p><hr><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Le Dashboard affiche quatre blocs de statistiques, calculées en temps réel depuis l&#39;API Gmail :</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Dashboard complète avec les 4 blocs</em></p></blockquote><hr><h2 id="top-expediteurs" tabindex="-1">Top expéditeurs <a class="header-anchor" href="#top-expediteurs" aria-label="Permalink to &quot;Top expéditeurs&quot;">​</a></h2><p>Un classement des expéditeurs qui vous envoient le plus de mails, avec deux vues :</p><ul><li><strong>Par nombre de mails</strong> : qui inonde votre boîte</li><li><strong>Par taille totale</strong> : qui consomme le plus d&#39;espace</li></ul><p>Ce classement est utile pour identifier rapidement les expéditeurs à nettoyer ou à bloquer.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : graphique Top expéditeurs (barres horizontales)</em></p></blockquote><hr><h2 id="mails-les-plus-volumineux" tabindex="-1">Mails les plus volumineux <a class="header-anchor" href="#mails-les-plus-volumineux" aria-label="Permalink to &quot;Mails les plus volumineux&quot;">​</a></h2><p>Liste des mails les plus gros de votre boîte, triés par taille décroissante. Cliquez sur un mail pour l&#39;ouvrir et décider si vous souhaitez le supprimer ou l&#39;archiver.</p><p>Idéal pour libérer rapidement de l&#39;espace dans votre quota Gmail.</p><hr><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2><p>Graphique en courbe montrant l&#39;évolution du volume de mails reçus par mois. Permet d&#39;identifier les pics d&#39;activité et les tendances.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : graphique Timeline (courbe mensuelle)</em></p></blockquote><hr><h2 id="repartition-des-labels" tabindex="-1">Répartition des labels <a class="header-anchor" href="#repartition-des-labels" aria-label="Permalink to &quot;Répartition des labels&quot;">​</a></h2><p>Graphique en camembert (ou donut) montrant la distribution de vos labels Gmail. Utile pour comprendre comment vos mails sont organisés.</p><hr><h2 id="statistiques-des-archives" tabindex="-1">Statistiques des archives <a class="header-anchor" href="#statistiques-des-archives" aria-label="Permalink to &quot;Statistiques des archives&quot;">​</a></h2><p>En plus des statistiques Gmail, le Dashboard affiche les statistiques de vos archives locales :</p><ul><li>Nombre de mails archivés</li><li>Taille totale des archives sur le NAS</li><li>Nombre de pièces jointes archivées</li></ul><hr><h2 id="cache-et-rafraichissement" tabindex="-1">Cache et rafraîchissement <a class="header-anchor" href="#cache-et-rafraichissement" aria-label="Permalink to &quot;Cache et rafraîchissement&quot;">​</a></h2><p>Les statistiques sont mises en cache pendant 15 minutes dans Redis pour éviter de surcharger l&#39;API Gmail. Le Dashboard affiche toujours les données les plus récentes disponibles.</p><p>Pour forcer un rafraîchissement, rechargez la page.</p>',31)])])}const m=a(t,[["render",l]]);export{h as __pageData,m as default};
